Python application:
from flask import Flask, request, render_template
import psycopg2

app = Flask(__name__)

def get_connection():
    return psycopg2.connect(database="testdb", user="postgres",
                            password="pass", host="127.0.0.1", port="5432")

@app.route("/")
def index():
    return render_template("index.html")

@app.route("/add")
def add():
    return render_template("add.html")

@app.route("/savedetails", methods=["POST"])
def saveDetails():
    conn = get_connection()
    cur = conn.cursor()
    email = request.form["email"]
    first_name = request.form["first_name"]
    last_name = request.form["last_name"]
    cur.execute(
        "INSERT INTO candidate (email_id, first_name, last_name) VALUES (%s, %s, %s)",
        (email, first_name, last_name)
    )
    conn.commit()
    cur.close()
    conn.close()
    return "Record saved successfully"

@app.route("/viewall")
def viewAll():
    conn = get_connection()
    cur = conn.cursor()
    cur.execute("SELECT * FROM candidate")
    results = cur.fetchall()
    cur.close()
    conn.close()
    return render_template("viewall.html", rows=results)

if __name__ == "__main__":
    app.run(host="127.0.0.1", port=5000, debug=True)
